import"./hoisted.kJBJfzdI.js";document.querySelectorAll("details").forEach(e=>{const i=e.querySelector("summary"),t=e.querySelector(".faq-body");i.addEventListener("click",r=>{if(r.preventDefault(),e.open){const o=t.animate([{height:t.scrollHeight+"px"},{height:"0px"}],{duration:260,easing:"cubic-bezier(0.4, 0, 0.2, 1)"});o.onfinish=()=>e.removeAttribute("open")}else e.setAttribute("open",""),t.animate([{height:"0px"},{height:t.scrollHeight+"px"}],{duration:300,easing:"cubic-bezier(0.4, 0, 0.2, 1)"})})});
